item.description:
 &lt;p&gt;aria2.conf设置aira2.conf文件&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter hljs&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;41&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;42&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;43&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;44&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;45&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;46&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;47&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;48&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;49&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;50&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;51&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;52&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;53&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;54&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;55&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;56&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;57&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;58&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;59&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;60&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;61&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;62&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;63&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;64&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;65&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;66&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;67&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;68&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;69&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;70&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;71&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;72&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;73&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;74&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;75&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;76&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;77&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;78&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;79&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;80&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;81&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;82&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;83&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;84&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;85&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;86&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;87&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;88&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;89&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;90&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;91&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;92&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;93&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;94&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;95&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;96&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;97&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;98&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;99&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;100&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;101&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;102&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;103&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;104&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;105&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;106&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;107&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;108&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;109&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;110&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;111&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;112&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;113&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;114&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;115&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;116&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;117&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;118&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;119&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;120&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;121&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;122&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;123&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;124&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;125&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;126&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;127&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;128&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;129&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;130&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;131&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;132&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;133&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;134&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;135&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;136&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;137&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;138&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;139&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;140&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;141&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;142&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;143&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;144&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;145&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;146&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;147&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;148&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;149&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;150&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;151&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;152&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;153&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;154&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;155&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;156&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;157&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;158&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;159&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;160&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;161&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;162&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;163&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;164&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;165&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;166&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;167&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;168&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;169&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;170&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;171&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;172&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;173&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs rst&#34;&gt;#下载文件默认保存路径&lt;br&gt;&amp;lt;code&amp;gt;dir=F:\MyDownload\Aria2\&lt;br&gt;### 日志文件保存路径及级别&lt;br&gt;log=E:\Aria2\aria2.log&lt;br&gt;log-level=error&lt;br&gt;# 从会话中读取任务&lt;br&gt;input-file=E:\Aria2\aria2.session&lt;br&gt;# 在Aria2退出时保存`错误/未完成`的下载任务到会话文件&lt;br&gt;save-session=E:\Aria2\aria2.session&lt;br&gt;#配置dht.dat文件存放位置&lt;br&gt;dht-file-path=E:\Aria2\dht.dat&amp;lt;/code&amp;gt;&lt;br&gt;# 定时保存会话, 0为退出时才保存, 需1.16.1以上版本, 默认:0&lt;br&gt;save-session-interval=60&lt;br&gt;# 强制保存会话, 即使任务已经完成, 默认:false&lt;br&gt;# 较新的版本开启后会在任务完成后依然保留.aria2文件&lt;br&gt;force-save=true&lt;br&gt;&lt;br&gt;# 下载选项&lt;br&gt;# 最大同时下载任务数, 运行时可修改, 默认:5&lt;br&gt;max-concurrent-downloads=5&lt;br&gt;# 断点续传&lt;br&gt;continue=true&lt;br&gt;# 整体下载速度限制, 运行时可修改, 默认:0 &lt;br&gt;max-overall-download-limit=5M&lt;br&gt;# 单个任务下载速度限制, 默认:0&lt;br&gt;max-download-limit=10M&lt;br&gt;# 整体上传速度限制, 运行时可修改, 默认:0&lt;br&gt;max-overall-upload-limit=1K&lt;br&gt;# 单个任务上传速度限制, 默认:0&lt;br&gt;max-upload-limit=1K&lt;br&gt;&lt;br&gt;# Http/FTP 选项&lt;br&gt;# 连接超时，建立链接后失效&lt;br&gt;connect-timeout=120&lt;br&gt;# 最小速度限制&lt;br&gt;# 当下载速度低于此选项设置的值(B/s) 时将会关闭连接. 0 表示不设置最小速度限制. &lt;br&gt;lowest-speed-limit=1K&lt;br&gt;# 同一服务器连接数, 添加时可指定, 默认:1,范围1-16&lt;br&gt;max-connection-per-server=15&lt;br&gt;# 文件未找到重试次数&lt;br&gt;# 设置为 0 将会禁用此选项&lt;br&gt;max-file-not-found=0&lt;br&gt;# 最小文件分片大小, 添加时可指定, 取值范围1M -1024M, 默认:20M&lt;br&gt;# 假定size=10M, 文件为20MiB 则使用两个来源下载; 文件为15MiB 则使用一个来源下载&lt;br&gt;min-split-size=10M&lt;br&gt;# 单个任务最大线程数, 添加时可指定, 默认:5&lt;br&gt;split=5&lt;br&gt;# 检查证书&lt;br&gt;check-certificate=false&lt;br&gt;# 禁用缓存&lt;br&gt;http-no-cache=true&lt;br&gt;# 磁盘缓存&lt;br&gt;# 如果设置为 0, 将禁用磁盘缓存. 此功能将下载的数据缓存在内存中&lt;br&gt;# 最多占用此选项设置的字节数. &lt;br&gt;disk-cache=32M&lt;br&gt;# FTP Specific Options&lt;br&gt;&lt;br&gt;# BT/PT Setting&lt;br&gt;# 本地节点查找, PT需要禁用, 默认:false&lt;br&gt;bt-enable-lpd=true&lt;br&gt;#最大连接节点数&lt;br&gt;#设置每个BT下载的最大连接节点数. 0 表示不限制.&lt;br&gt;bt-max-peers=100&lt;br&gt;# 自动BT任务&lt;br&gt;follow-torrent=true&lt;br&gt;&lt;br&gt;# 启用 DHT (IPv6)&lt;br&gt;# 启用 IPv6 DHT 功能. 如果种子设置为私有, 即使此选项设置为&amp;quot;是&amp;quot;, aria2 也不会启用&lt;br&gt;enable-dht6=true&lt;br&gt;enable-dht=true&lt;br&gt;dht-listen-port=6881-6999&lt;br&gt;&lt;br&gt;# 不检查已经下载的文件&lt;br&gt;# 不检查之前下载文件中每个分片的哈希值.&lt;br&gt;bt-seed-unverified=false&lt;br&gt;# 做种前检查文件哈希&lt;br&gt;# 如果设置为&amp;quot;是&amp;quot;, 当使用 --check-integrity 选项完成哈希检查及文件完成后才继续做种. 如果您希望仅当文件损坏或未完成时检查文件, 请设置为&amp;quot;否&amp;quot;. 此选项仅对 BT 下载有效&lt;br&gt;bt-hash-check-seed=false&lt;br&gt;# 保存上传的种子文件&lt;br&gt;rpc-save-upload-metadata=true&lt;br&gt;# 删除未选择的文件&lt;br&gt;# 当 BT 任务完成后删除未选择的文件. 要选择需要下载的文件, 请使用 --select-file选项. &lt;br&gt;# 如果没有选择, 则所有文件都默认为需要下载. 此选项会从磁盘上直接删除文件, &lt;br&gt;# 请谨慎使用此选项.&lt;br&gt;bt-remove-unselected-file=false&lt;br&gt;# 每个种子限速, 对少种的PT很有用, 默认:50K&lt;br&gt;bt-request-peer-speed-limit=2M&lt;br&gt;#做种时间&lt;br&gt;seed-time=0&lt;br&gt;#优先下载&lt;br&gt;bt-prioritize-piece=head=10M&lt;br&gt;# 当种子的分享率达到这个数时, 自动停止做种, 0为一直做种, 默认:1.0&lt;br&gt;seed-ratio=1.0&lt;br&gt;&lt;br&gt;# Metalink Specific Options&lt;br&gt;# RPC Options&lt;br&gt;# 启用RPC, 默认:false&lt;br&gt;enable-rpc=true&lt;br&gt;# 种子文件下载完后暂停&lt;br&gt;pause-metadata=false&lt;br&gt;&lt;br&gt;#种子交换, PT需要禁用, 默认:true&lt;br&gt;enable-peer-exchange=true&lt;br&gt;# 允许所有来源, 默认:false&lt;br&gt;rpc-allow-origin-all=true&lt;br&gt;# 允许非外部访问, 默认:false&lt;br&gt;rpc-listen-all=true&lt;br&gt;#保存上传的种子文件&lt;br&gt;rpc-save-upload-metadata=true&lt;br&gt;# 启用加密后 RPC 服务需要使用 https 或者 wss 协议连接&lt;br&gt;rpc-secure=false&lt;br&gt;&lt;br&gt;# Advanced Options&lt;br&gt;#启用后台进程&lt;br&gt;daemon=true&lt;br&gt;# 禁用IPV6，默认：false&lt;br&gt;disable-ipv6=true&lt;br&gt;# 启用 MMap&lt;br&gt;# 内存中存放映射文件. 当文件空间没有预先分配至, 此选项无效. 参见 --file-allocation.&lt;br&gt;enable-mmap=true&lt;br&gt;# 文件分配方法  &lt;br&gt;# &amp;quot;prealloc&amp;quot;会在下载开始前预先分配空间.&lt;br&gt;# ext4 (带扩展支持), btrfs, xfs 或 NTFS (仅 MinGW 构建), &amp;quot;falloc&amp;quot; 是最好的选择&lt;br&gt;file-allocation=falloc &lt;br&gt;#最多下载结果 下载结果包括已完成/错误/已删除的下载&lt;br&gt;max-download-result=30&lt;br&gt;# 文件分配限制&lt;br&gt;# 不对比此参数设置大小小的分配文件. 您可以增加数值的单位 K 或 M &lt;br&gt;#no-file-allocation-limit=32M&lt;br&gt;# 强制顺序&lt;br&gt;force-sequential=true&lt;br&gt;# 启用参数化 URI 支持&lt;br&gt;# 您可以指定部分的集合: http://&amp;#123;sv1,sv2,sv3&amp;#125;/foo.iso. &lt;br&gt;# 同时您也可以使用步进计数器指定数字化的序列: http://host/image[000-100:2].img. &lt;br&gt;# [需使用 -z 选项]&lt;br&gt;# 步进计数器可以省略.&lt;br&gt;parameterized-uri=true&lt;br&gt;#延迟加载&lt;br&gt;deferred-input=true&lt;br&gt;&lt;br&gt;# bt-tracker=BT服务器（多个服务器之间用,分开）&lt;br&gt;bt-tracker=udp://tracker.coppersurfer.tk:6969/announc,udp://tracker.leechers-paradise.org:6969/announc,udp://tracker.opentrackr.org:1337/announc,udp://p4p.arenabg.com:1337/announc,udp://9.rarbg.to:2710/announc,udp://9.rarbg.me:2710/announc,udp://exodus.desync.com:6969/announc,udp://tracker.pomf.se:80/announc,udp://tracker.openbittorrent.com:80/announc,udp://tracker.tiny-vps.com:6969/announc,udp://open.stealth.si:80/announc,udp://denis.stalker.upeer.me:6969/announc,udp://tracker.torrent.eu.org:451/announc,udp://tracker.moeking.me:6969/announc,udp://tracker.cyberia.is:6969/announc,udp://ipv4.tracker.harry.lu:80/announc,udp://tracker3.itzmx.com:6961/announc,udp://open.demonii.si:1337/announc,udp://explodie.org:6969/announc,udp://valakas.rollo.dnsabr.com:2710/announe&lt;br&gt;&lt;br&gt;## 执行额外命令 ##&lt;br&gt;&lt;br&gt;# 下载停止后执行的命令&lt;br&gt;# 从 正在下载 到 删除、错误、完成 时触发。暂停被标记为未开始下载，故与此项无关。&lt;br&gt;on-download-stop=/etc/aria2/delete.sh&lt;br&gt;&lt;br&gt;# 下载完成后执行的命令&lt;br&gt;# 此项未定义则执行 下载停止后执行的命令 (on-download-stop)&lt;br&gt;on-download-complete=/etc/aria2/clean.sh&lt;br&gt;&lt;br&gt;# 下载错误后执行的命令&lt;br&gt;# 此项未定义则执行 下载停止后执行的命令 (on-download-stop)&lt;br&gt;#on-download-error=&lt;br&gt;&lt;br&gt;# 下载暂停后执行的命令&lt;br&gt;#on-download-pause=&lt;br&gt;&lt;br&gt;# 下载开始后执行的命令&lt;br&gt;#on-download-start=&lt;br&gt;&lt;br&gt;# BT 下载完成后执行的命令&lt;br&gt;#on-bt-download-complete=&lt;br&gt;&lt;br&gt;#注意修改aria2.conf文件中以下选项：&lt;br&gt;#下载文件保存路径，改为你想要的&lt;br&gt;#dir=D:\MyDownload\aria2\&lt;br&gt;# 日志文件，路径D:\aria2\，改为你安装aria2的路径&lt;br&gt;&amp;lt;code&amp;gt;#log=D:\aria2\aria2.log&lt;br&gt;#input-file=D:\aria2\aria2.session&lt;br&gt;#save-session=D:\aria2\aria2.session&amp;lt;/code&amp;gt;&lt;br&gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;a href=&#34;https://github.com/P3TERX/aria2.conf&#34;&gt;一键安装及配置开源项目：&lt;/a&gt;&lt;/p&gt;
